Trigger.script:
if table.contains(gc.InRoom, target) then if table.contains(gc.target_list, target) then if not table.contains(gc.SoulList, target) then table.insert(gc.SoulList, target)
gc.SoulTimers[tostring(target)] = tempTimer(25, function() --If you try to hit them and they can't be but are still in the Room List they might be a soul... Or a DAMN SERPENT! Screw EVADE! Heheh table.remove(gc.SoulList, table.index_of(gc.SoulList, target)) killTimer(gc.SoulTimers[tostring(target)]) end) end
if gc.Settings.SetTarget then boxAlert("Did not detect target here!", "yellow", "white", 1, 1) -- gc.Burstcheck(tostring(target)) else boxAlert("Did not detect target here!", "yellow", "white", 1, 1) end end end

--This child trigger should take each name filtered to it and run adding them to the SoulList (Code below) for 25 seconds
if not table.contains(gc.SoulList, matches[2]) then table.insert(gc.SoulList, matches[2])
gc.SoulTimers[tostring(matches[2])] = tempTimer(25, function() table.remove(gc.SoulList, table.index_of(gc.SoulList, matches[2])) killTimer(gc.SoulTimers[tostring(matches[2])]) end) end cecho("\n<OrangeRed>[GroundeCombat] <LemonChiffon>"..matches[2].." <grey>is a soul!")

--This makes temp triggers for each name of the person in the list being loaded --These temp triggers when they fire will add the name to a table to use later --The loop stores the temptrigger ID's to delete them after qw to clean up
gc.NameCheck = {} gc.TempTargetList2 = {}
for _, name in pairs(gc.TempTargetList) do gc.NameCheck[name] = tempTrigger(name, function() table.insert(gc.TempTargetList2, name) end, 1) end

ScriptGroup.script:
--Set all initial default variables, some will be overwritten when settings finish loading 
gc = gc or {}
gc.Settings = gc.Settings or {}
gc_list = gc_list or {}

gc.Settings.TargetSwitch = gc.Settings.TargetSwitch or "manual"
gc.Settings.SetEnemy = gc.Settings.SetEnemy or "Yep"
gc.Settings.SetTarget = gc.Settings.SetTarget or false
gc.Settings.OverRide = gc.Settings.OverRide or false
gc.Settings.MoveReporting = gc.Settings.MoveReporting or false
gc.Settings.AffCalling = gc.Settings.AffCalling or false
gc.Settings.WallCalling = gc.Settings.WallCalling or false
gc.Settings.CityTargeting = gc.Settings.CityTargeting or "none"
gc.Settings.PartyGag = gc.Settings.PartyGag or false
gc.report = gc.report or "pt"

gc.ListEnemied = gc.ListEnemied or "No"
gc.IsLeader = gc.IsLeader or false
gc.Remove = gc.Remove or false
gc.target_list = gc.target_list or {}
gc.BurstTimers = gc.BurstTimer or {}
gc.bursted = gc.bursted or {}
gc.InRoom = gc.InRoom or {}
gc.Leader = gc.Leader or ""
gc.Callers = gc.Callers or {}
gc.SoulList = gc.SoulList or {}
gc.SoulTimers = gc.SoulTimers or {}
gc.ToTarget = gc.ToTarget or "none"

gc.TempTargetList = gc.TempTargetList or {}

gc.DontTarget = gc.DontTarget or {}
